// Henderson Poverty Line thresholds (annual gross assessable income)
const SINGLE_HPL_MULTIPLIER = 1.20;  // 120% HPL
const COUPLE_HPL_MULTIPLIER = 1.60;  // 160% HPL

function IsEligible(income: Currency; isCouple: Boolean): Boolean;
var threshold: Currency;
begin
  threshold := CurrentHPL *
    IfThen(isCouple, COUPLE_HPL_MULTIPLIER, SINGLE_HPL_MULTIPLIER);
  Result := income <= threshold;
end;

